function pickText(obj) {
  if (!obj || typeof obj !== "object") return "";
  const candidates = ["content","text_message","text","response","message","output"];
  for (const k of candidates) {
    const v = obj[k];
    if (typeof v === "string" && v.trim()) return v;
  }
  for (const v of Object.values(obj)) {
    if (typeof v === "string" && v.trim()) return v;
  }
  return "";
}

let mensagemRaw = "";
try { mensagemRaw = pickText($input.first()?.json) || ""; } catch (e) {}
if (!mensagemRaw) {
  try { mensagemRaw = pickText($("Stella1").first()?.json) || ""; } catch (e) {}
}

const mensagem = String(mensagemRaw).replace(/\r\n/g,"\n").replace(/\u00A0/g," ").trim();
if (!mensagem) return [{ json: { output: "" } }];

const isStructuredTemplate = (txt) => {
  const sep = (txt.match(/━{3,}/g) || []).length;
  const emo = (txt.match(/^[📋✅🚚📍💳🛒💰👤📱🏠🔖]/gmu) || []).length;
  return sep >= 1 || emo >= 3;
};
if (isStructuredTemplate(mensagem)) return [{ json: { output: mensagem } }];

const isLikelySignatureHead = (line) =>
  /^(atenciosamente|com\s+carinho|abraços|abracos|obrigad[oa]|grato|grata|cordialmente|respeitosamente|att\.?)\b/i.test((line ?? "").trim());

const hasOnlyShortLines = (block) => {
  const lines = (block ?? "").split("\n").map(l => l.trim()).filter(Boolean);
  if (!lines.length) return false;
  const avg = lines.reduce((a,b) => a + b.length, 0) / lines.length;
  return avg <= 28 && lines.every(l => l.length <= 50);
};

const sentenceSplit = (p) => {
  p = (p ?? "").trim();
  if (!p || hasOnlyShortLines(p)) return [p].filter(Boolean);
  const parts = p.match(/[^.!?]+(?:[.!?]+["'"]?)(?=\s+|$)|[^.!?]+$/g) || [p];
  const ABBR = /(?:\b(Sr|Sra|Srta|Dr|Dra|Prof|Profa|vs|p|ex|etc|aprox|pg|fig|cap)\.)$/i;
  const fixed = [];
  for (const curRaw of parts) {
    const cur = (curRaw ?? "").trim();
    if (!cur) continue;
    if (fixed.length && ABBR.test(fixed[fixed.length-1].trim()))
      fixed[fixed.length-1] = fixed[fixed.length-1].trim() + " " + cur;
    else fixed.push(cur);
  }
  return fixed;
};

const groupSentences = (sentences, maxChars=400, maxPerGroup=3) => {
  const groups = []; let buf = ""; let cnt = 0;
  const flush = () => { if (buf.trim()) groups.push(buf.trim()); buf = ""; cnt = 0; };
  const isUrl = s => /^(https?:\/\/\S+|www\.\S+|[\w.+-]+@[\w.-]+\.[a-zA-Z]{2,})$/i.test((s ?? "").trim());
  for (const sRaw of sentences) {
    const s = (sRaw ?? "").trim(); if (!s) continue;
    const tent = buf ? buf + " " + s : s;
    if ((tent.length > maxChars || cnt+1 > maxPerGroup || isUrl(s)) && buf) flush();
    buf = buf ? buf + " " + s : s; cnt++;
    if (buf.length >= maxChars * 0.9) flush();
  }
  flush(); return groups;
};

const blocks = mensagem.split(/\n{2,}/).map(b => b.trim()).filter(Boolean);
const finalBlocks = [];
for (let i = 0; i < blocks.length; i++) {
  const b = blocks[i];
  const firstLine = b.split("\n")[0] ?? "";
  const isSig = isLikelySignatureHead(firstLine) || (i === blocks.length-1 && hasOnlyShortLines(b));
  if (isSig || (b.length <= 500 && b.includes("\n")) || b.length <= 420) { finalBlocks.push(b); continue; }
  finalBlocks.push(...groupSentences(sentenceSplit(b), 400, 3));
}

const outputs = finalBlocks.map(s => s.replace(/[ \t]+\n/g,"\n").trim()).filter(Boolean).map(s => ({ json: { output: s } }));
return outputs.length ? outputs : [{ json: { output: mensagem } }];

const URLS = {
  cardapio:     "https://tjufzxqkiqcspdmlllfb.supabase.co/storage/v1/object/public/stella/cardapio.jpg",
  combopromo:   "https://tjufzxqkiqcspdmlllfb.supabase.co/storage/v1/object/public/stella/combopromo.jpg",
  combo_kids:   "https://tjufzxqkiqcspdmlllfb.supabase.co/storage/v1/object/public/stella/combokids.jpg",
  compartilhar: "https://tjufzxqkiqcspdmlllfb.supabase.co/storage/v1/object/public/stella/compartilhar.jpg"
};

function pickText(obj) {
  if (!obj || typeof obj !== "object") return "";
  const keys = ["text_message","text","response","message","content","output"];
  for (const k of keys) {
    const v = obj[k];
    if (typeof v === "string" && v.trim()) return v;
  }
  for (const v of Object.values(obj)) {
    if (typeof v === "string" && v.trim()) return v;
  }
  return "";
}

const raw = (pickText($input.first()?.json) || "").trim();
if (!raw) return [{ json: { type: "text", content: "" } }];

const segments = [];
const tagRegex = /\[IMAGEM:(\w+)\]/g;
let lastIndex = 0;
let match;

while ((match = tagRegex.exec(raw)) !== null) {
  const textBefore = raw.slice(lastIndex, match.index).trim();
  if (textBefore) segments.push({ type: "text", content: textBefore });
  const key = match[1];
  const url = URLS[key];
  if (url) segments.push({ type: "image", url, key });
  lastIndex = match.index + match[0].length;
}

const textAfter = raw.slice(lastIndex).trim();
if (textAfter) segments.push({ type: "text", content: textAfter });

if (segments.length === 0) return [{ json: { type: "text", content: raw } }];
return segments.map(s => ({ json: s }));

const payload = {
  modo_demanda: $('Redis_ModoDemanda').first().json.modo_demanda,
  horarios: $('Redis_Horarios').first().json.horarios ? JSON.parse($('Redis_Horarios').first().json.horarios) : null,
  entregas: $('Redis_Entregas').first().json.entregas ? JSON.parse($('Redis_Entregas').first().json.entregas) : null,
  cardapio: $('Redis_Cardapio').first().json.cardapio ? JSON.parse($('Redis_Cardapio').first().json.cardapio) : null,
  prompt_custom: $('Redis_Prompt').first().json.system_prompt || '',
};

const diasSemana = ["domingo", "segunda", "terca", "quarta", "quinta", "sexta", "sabado"];
const diaSemanaHoje = diasSemana[new Date().getDay()];
const hjConf = payload.horarios ? payload.horarios[diaSemanaHoje] : null;

// Constrói O CARDÁPIO (Apenas itens disponíveis, respeitando dias_validos e pausado_hoje)
let cardapioText = '';
if (payload.cardapio) {
  payload.cardapio.categorias.forEach(cat => {

    // BUG 2 CORRIGIDO: Pula categoria se dias_validos existir e hoje não estiver na lista
    if (cat.dias_validos && cat.dias_validos.length > 0) {
      if (!cat.dias_validos.includes(diaSemanaHoje)) return;
    }

    cardapioText += `\n#* ${cat.nome.toUpperCase()} *\n`;
    if (cat.descricao) cardapioText += `${cat.descricao}\n`;

    // BUG 3 CORRIGIDO: Filtra também por pausado_hoje
    cat.itens
      .filter(i => i.disponivel && !i.pausado_hoje)
      .forEach(item => {
        cardapioText += `- ${item.nome}: R$ ${item.preco.toFixed(2).replace('.', ',')} `;
        if (item.preco_cento) cardapioText += `(Cento: R$ ${item.preco_cento.toFixed(2).replace('.', ',')}) `;

        // CORREÇÃO: Mapeamento do Pedido Mínimo adicionado aqui
        if (item.pedido_minimo) cardapioText += `[Pedido Mínimo: ${item.pedido_minimo} un] `;

        if (item.requer_antecedencia_horas > 0) cardapioText += `[Antecedência: ${item.requer_antecedencia_horas}h] `;
        if (item.observacao) cardapioText += `[${item.observacao}]`;
        cardapioText += '\n';
      });
  });
} else {
  cardapioText = '[ERRO: Cardápio Vazio - AVISE A PROPRIETÁRIA]';
}

// INSTRUÇÕES FORÇADAS DE ESTADO
const instrucoesDemanda = payload.modo_demanda === 'true'
  ? "\n\n⚠️ INSTRUÇÃO CRÍTICA MODO PÂNICO: A loja está com MUITA DEMANDA agora. Avise ao cliente logo na primeira mensagem que os pedidos podem demorar mais que o normal para ficarem prontos! ⚠️\n\n"
  : "";

// BUG 1 CORRIGIDO: removida referência a payload.loja_aberta que nunca existiu
const instrucoesFechada = (hjConf && !hjConf.aberto)
  ? "\n\n⛔ MODO FECHADO: A loja está FECHADA no momento. Informe ao cliente que o atendimento ou entrega só ocorrerão no próximo dia/horário letivo, mas que você anotará o pedido! ⛔\n\n"
  : "";

const entregasText = payload.entregas
  ? JSON.stringify(payload.entregas.zonas)
  : "Taxas baseadas no bairro: Centro (R$8), Intermediários (R$10), Distantes (R$12)";

const systemMessage = `${payload.prompt_custom}\n\n---\n\n\nCONTEXTO AO VIVO DA LOJA AGORA:\n- Dia da semana: ${diaSemanaHoje}\n- Horário hoje: ${hjConf ? (hjConf.aberto ? hjConf.abertura + ' às ' + hjConf.fechamento : 'Fechada hoje') : 'Desconhecido'}\n- Limite de Pedidos hoje: ${hjConf ? hjConf.limite_pedidos : 'N/A'}\n- Taxas de Entrega atuais:\n${entregasText}\n${instrucoesDemanda}${instrucoesFechada}\n\nCARDÁPIO ATIVO NESTE INSTANTE:\n${cardapioText}`;

const out = [];
for (const item of $input.all()) {
  out.push({
    json: {
      ...item.json,
      systemPrompt: systemMessage
    }
  });
}
return out;

const raw = String($input.first()?.json?.output || $input.first()?.json?.text || $input.first()?.json?.text_message || $input.first()?.json?.response || '').trim();

// Frases que indicam que a Stella precisa de ajuda humana
const FALLBACK_PATTERNS = [
  /verificar com (?:as |nossas )?atendentes/i,
  /ver com (?:as )?atendentes/i,
  /passar (?:sua |a )?solicita[cç][aã]o para (?:nossa )?equipe/i,
  /atendentes v[aã]o (?:te )?(enviar|confirmar|ver|avisar)/i,
  /vou(?:\s+te)?\s+(?:verificar|passar|checar)\s+com/i,
  /eles te retornam/i,
  /(?:nossa )?equipe (?:te |irá |vai )?(retornar|atender|responder|contatar)/i,
];

// Frases que indicam confirmação de pedido (NÃO é fallback)
const ORDER_CONFIRMATION = /anotado aqui|pedido confirmado|pedido registrado|agradece|obrigad[oa] pela prefer/i;

let isFallback = FALLBACK_PATTERNS.some(p => p.test(raw));

// Se é confirmação de pedido, NÃO é fallback
if (isFallback && ORDER_CONFIRMATION.test(raw)) {
  isFallback = false;
}

let tipo = 'outro';
if (/bairro|zona/i.test(raw)) tipo = 'bairro_fora_zona';
else if (/status|pedido.*anterior|andamento/i.test(raw)) tipo = 'pedido_anterior';
else if (/maquininha/i.test(raw)) tipo = 'maquininha';
else if (/tempinho.*pronto|quanto tempo/i.test(raw)) tipo = 'retirada_imediata';
else if (/disponibilidade|item/i.test(raw)) tipo = 'item_indisponivel';
else if (/congelad|cru/i.test(raw)) tipo = 'congelados';
else if (/link.*pagamento/i.test(raw)) tipo = 'link_pagamento';

return [{
  json: {
    isFallback,
    tipo,
    mensagem: raw.substring(0, 500)
  }
}];

